parameters.functionCode:
// ─── Merge + Compare + Decide (UNIVERSAL) ───
// Works with ANY world file. Uses top-level fields from the Simulate node.
// No hardcoded metric names or world-specific logic.

// Collect all simulation profiles from input items
const profiles = {};
for (const item of items) {
  const profileName = item.json.profile;
  profiles[profileName] = {
    viable: item.json.viable,
    viability: item.json.viability,
    collapsed: item.json.collapsed,
    worldName: item.json.worldName,
    report: item.json.report,
    narrative: item.json.narrative,
    stateDeltas: item.json.stateDeltas || {},
    simulation: item.json.simulation || {}
  };
}

const profileNames = Object.keys(profiles);
const profileList = Object.values(profiles);

// ─── Universal Decision Logic ───
const allViable = profileList.every(p => p.viable);
const anyCollapsed = profileList.some(p => p.collapsed);
const anyCritical = profileList.some(p => p.viability === 'CRITICAL' || p.viability === 'MODEL_COLLAPSES');
const worldName = profileList[0]?.worldName || 'Unknown';

// Find expected/middle profile for nuanced decisions
const expectedProfile = profiles.expected || profiles.baseline || profileList[Math.floor(profileList.length / 2)];
const expectedOk = expectedProfile?.viable;

let decision, recommendation;
if (allViable) {
  decision = 'APPROVE';
  recommendation = `All ${profileNames.length} scenarios remain healthy. Safe to proceed.`;
} else if (expectedOk && !anyCollapsed) {
  decision = 'APPROVE_WITH_GUARDRAILS';
  recommendation = 'Expected case is stable, but edge cases show degradation. Proceed with monitoring.';
} else if (anyCritical || anyCollapsed) {
  decision = 'BLOCK';
  recommendation = 'System reaches CRITICAL or collapses under realistic conditions. Do not proceed without changes.';
} else {
  decision = 'REVIEW';
  recommendation = 'Mixed results across profiles. Requires human review before proceeding.';
}

// ─── Build the universal report ───
const lines = [];
lines.push(`===== SIMULATION COMPARISON: ${worldName} =====`);
lines.push(`Profiles tested: ${profileNames.join(', ')}`);
lines.push('');

// Per-profile narratives (from the governance engine — world-aware)
for (const [name, profile] of Object.entries(profiles)) {
  const label = name.replace(/_/g, ' ').toUpperCase();
  const v = profile.viability || 'UNKNOWN';
  const collapsed = profile.collapsed ? ' [COLLAPSED]' : '';
  lines.push(`--- ${label}: ${v}${collapsed} ---`);
  if (profile.report) {
    lines.push(profile.report);
  }
  // State changes (dynamic — whatever vars the world defines)
  const deltas = profile.stateDeltas || {};
  const deltaEntries = Object.entries(deltas);
  if (deltaEntries.length > 0) {
    lines.push('  State changes:');
    for (const [key, delta] of deltaEntries) {
      if (delta && delta.from !== undefined) {
        lines.push(`    ${key}: ${delta.from} -> ${delta.to}`);
      }
    }
  }
  lines.push('');
}

lines.push('--- DECISION ---');
lines.push(`  ${decision}`);
lines.push(`  ${recommendation}`);

const report = lines.join('\n');

return [{
  json: {
    decision,
    recommendation,
    report,
    worldName,
    profileCount: profileNames.length,
    allViable,
    anyCollapsed,
    profiles: Object.fromEntries(
      Object.entries(profiles).map(([name, p]) => [name, {
        viability: p.viability,
        viable: p.viable,
        collapsed: p.collapsed,
        stateDeltas: p.stateDeltas,
        narrative: p.narrative
      }])
    )
  }
}];
